        for (int i = 0; i < list.Count; i++)
        {
            var old = list[i];
            var @new = RewriteExpression(old.Value);
            if (!ReferenceEquals(old.Value, @new))
            {
                result ??= [.. list.Take(i)];
            }
            result?.Add(result is null ? old : old with { Value = @new });
        }
        return result is null ? list : result;
    }

