        var @else = node.Else is {} __Else ? RewriteStatement(__Else) : null;
        bool _same = ReferenceEquals(condition, node.Condition)
                  && ReferenceEquals(then, node.Then)
                  && ReferenceEquals(@else, node.Else);
        if (_same) return node;
        return node with { Condition = condition, Then = then, Else = @else };
