            if (!armSame)
            {
                arms ??= [.. node.Arms.Take(i)];
                arms.Add(arm with { Guard = newGuard, Value = newVal });
            }
            else arms?.Add(arm);
        }
        bool same = ReferenceEquals(subject, node.Subject) && arms is null;
        return same ? node : node with { Subject = subject, Arms = arms ?? node.Arms };
